changeSet.sql:
CREATE TABLE users_metadata (
id serial,
user_id int4 NOT NULL,
key character varying (255) NOT NULL,
value character varying (4096) NOT NULL,

CONSTRAINT pk_users_metadata PRIMARY KEY (id),
CONSTRAINT fk_users_metadata_to_technology_categories FOREIGN KEY (user_id)
REFERENCES users(id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);

CREATE INDEX i_users_metadata_technology_category_id ON
users_metadata USING btree (user_id);
CREATE UNIQUE INDEX ui_users_metadata_user_id_key ON
users_metadata (user_id, key);
